+        let reason = reasons
+            .iter()
+            .find(|entry| entry.code == code)
+            .unwrap_or_else(|| panic!("missing degraded reason code: {code}"));
+        assert_eq!(reason.reason_id, reason_id);
+        assert_eq!(reason.stage, stage);
+        assert!(!reason.consumer_action.trim().is_empty());
+    }
